-- Hotfix 26.2 — reconciliation for production databases with an incomplete legacy
-- migration history. This migration is deliberately additive: it never drops tables,
-- truncates rows, changes primary keys, or replays imports/seeds.
-- Inventory reconciled: profiles/social fields; problems/solutions/catalog provenance;
-- comments/comment_reports; favorites/reactions; contributions/contribution_audit;
-- audit_events; notifications; problem_timeline; storage image buckets and policies;
-- Sprint 20–24 triggers/RPCs and Sprint 25 map RPC grants.
create extension if not exists pgcrypto;

-- Tables absent from the confirmed snapshot. Definitions below reproduce the Sprint 20–24 contracts exactly.
create table if not exists public.reactions (
 id uuid primary key default gen_random_uuid(), user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,
 problem_id uuid references public.problems(id) on delete cascade, solution_id uuid references public.solutions(id) on delete cascade,
 reaction_type text not null, created_at timestamptz not null default timezone('utc', now()),
 constraint reactions_exactly_one_target_check check ((problem_id is not null)::integer + (solution_id is not null)::integer = 1),
 constraint reactions_type_check check (reaction_type in ('useful', 'liked', 'interesting')));
create table if not exists public.contributions (
 id uuid primary key default gen_random_uuid(), user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,
 problem_id uuid references public.problems(id) on delete cascade, solution_id uuid references public.solutions(id) on delete cascade,
 contribution_type text not null, payload jsonb not null, status text not null default 'pending', moderator_id uuid references auth.users(id) on delete set null,
 rejection_reason text, created_at timestamptz not null default timezone('utc', now()), reviewed_at timestamptz,
 constraint contributions_exactly_one_target_check check ((problem_id is not null)::integer + (solution_id is not null)::integer = 1),
 constraint contributions_status_check check (status in ('pending', 'reviewing', 'approved', 'rejected')),
 constraint contributions_type_check check (contribution_type in ('correction', 'update', 'evidence', 'general')),
 constraint contributions_payload_check check (jsonb_typeof(payload) = 'object' and payload <> '{}'::jsonb and jsonb_array_length(coalesce(payload->'changes', '[]'::jsonb)) > 0),
 constraint contributions_review_fields_check check ((status in ('pending', 'reviewing') and reviewed_at is null) or (status in ('approved', 'rejected') and reviewed_at is not null and moderator_id is not null)));
create table if not exists public.contribution_audit (
 id uuid primary key default gen_random_uuid(), contribution_id uuid not null references public.contributions(id) on delete cascade,
 moderator_id uuid not null references auth.users(id) on delete restrict, action text not null check (action in ('approved', 'rejected')),
 created_at timestamptz not null default timezone('utc', now()));
create table if not exists public.audit_events (
 id uuid primary key default gen_random_uuid(), actor_id uuid,
 event_type text not null check (event_type in ('auth.login_succeeded','auth.logout','auth.mfa_enabled','auth.mfa_disabled','problem.created','problem.updated','problem.deleted','solution.created','solution.updated','solution.deleted','contribution.approved','contribution.rejected','moderation.action','user.role_changed','security.unauthorized_attempt')),
 target_type text check (target_type is null or (length(trim(target_type)) between 1 and 50)), target_id uuid, metadata jsonb not null default '{}'::jsonb,
 created_at timestamptz not null default timezone('utc', now()), constraint audit_metadata_object check (jsonb_typeof(metadata) = 'object'), constraint audit_metadata_size check (pg_column_size(metadata) <= 4096), constraint audit_metadata_sensitive check (not (metadata ?| array['password','token','secret','session','credential','api_key','mfa_secret'])));
create table if not exists public.notifications (
 id uuid primary key default gen_random_uuid(), recipient_id uuid not null references auth.users(id) on delete cascade, actor_id uuid references auth.users(id) on delete set null,
 type text not null check (type in ('contribution.approved','contribution.rejected','comment.created','comment.replied','comment.reacted','favorite.content_updated','user.role_changed')),
 title text not null check (length(trim(title)) between 1 and 120), message text not null check (length(trim(message)) between 1 and 500), target_type text constraint notifications_target_type_check check (target_type is null or length(trim(target_type)) between 1 and 50), target_id uuid, action_url text constraint notifications_action_url_check check (action_url is null or (length(action_url) <= 500 and action_url like '/%' and left(action_url,2) <> '//' and action_url !~* '^(https?:|javascript:|data:)')),
 metadata jsonb not null default '{}'::jsonb check (jsonb_typeof(metadata)='object' and pg_column_size(metadata)<=4096), read_at timestamptz, created_at timestamptz not null default timezone('utc',now()));
create table if not exists public.problem_timeline (
 id uuid primary key default gen_random_uuid(), problem_id uuid not null, actor_id uuid,
 event_type text not null check (event_type in ('problem.created','problem.updated','problem.status_changed','problem.comment','problem.official_update','problem.inspection','problem.execution_started','problem.execution_finished','problem.reopened','problem.closed')),
 title text not null check (length(trim(title)) between 1 and 160), description text check (description is null or length(description)<=5000), status_before text,status_after text,official boolean not null default false,organization_name text,metadata jsonb not null default '{}'::jsonb check(jsonb_typeof(metadata)='object'),created_at timestamptz not null default timezone('utc',now()));

-- Existing tables can be partial. Additive columns use IF NOT EXISTS and nullable
-- defaults so existing rows are preserved (no ID regeneration and no seed replay).
alter table public.profiles add column if not exists website text, add column if not exists organization text, add column if not exists social_links jsonb not null default '{}'::jsonb;
alter table public.problems add column if not exists source_type text, add column if not exists source_name text, add column if not exists source_url text, add column if not exists source_published_at timestamptz, add column if not exists source_accessed_at timestamptz, add column if not exists source_verified_at timestamptz, add column if not exists source_metadata jsonb not null default '{}'::jsonb, add column if not exists imported_from_external_source boolean not null default false, add column if not exists latitude double precision, add column if not exists longitude double precision, add column if not exists geolocation_precision text, add column if not exists geolocation_source text, add column if not exists geocoded_at timestamptz;
alter table public.comments add column if not exists visibility text not null default 'visible', add column if not exists deleted boolean not null default false, add column if not exists edited boolean not null default false;
alter table public.favorites add column if not exists created_at timestamptz not null default timezone('utc',now());

-- Constraints are catalog-guarded because ADD CONSTRAINT has no IF NOT EXISTS.
do $$ begin
 if to_regclass('public.problems') is not null and not exists(select 1 from pg_constraint where conrelid='public.problems'::regclass and conname='problems_geolocation_pair_check') then alter table public.problems add constraint problems_geolocation_pair_check check ((latitude is null) = (longitude is null)) not valid; end if;
 if to_regclass('public.problems') is not null and not exists(select 1 from pg_constraint where conrelid='public.problems'::regclass and conname='problems_latitude_check') then alter table public.problems add constraint problems_latitude_check check (latitude is null or latitude between -90 and 90) not valid; end if;
 if to_regclass('public.problems') is not null and not exists(select 1 from pg_constraint where conrelid='public.problems'::regclass and conname='problems_longitude_check') then alter table public.problems add constraint problems_longitude_check check (longitude is null or longitude between -180 and 180) not valid; end if;
 if to_regclass('public.comments') is not null
    and exists(
      select 1
      from information_schema.columns
      where table_schema='public'
        and table_name='comments'
        and column_name='user_id'
    )
    and not exists(
      select 1
      from pg_constraint
      where conrelid='public.comments'::regclass
        and conname='comments_user_profile_fkey'
    )
  then
    alter table public.comments
      add constraint comments_user_profile_fkey
      foreign key(user_id)
      references public.profiles(id)
      on delete cascade
      not valid;
  end if;
end $$;

create unique index if not exists reactions_user_problem_type_unique on public.reactions(user_id,problem_id,reaction_type) where problem_id is not null;
create unique index if not exists reactions_user_solution_type_unique on public.reactions(user_id,solution_id,reaction_type) where solution_id is not null;
create index if not exists reactions_problem_summary_idx on public.reactions(problem_id,reaction_type) where problem_id is not null;
create index if not exists reactions_solution_summary_idx on public.reactions(solution_id,reaction_type) where solution_id is not null;
create index if not exists reactions_user_id_idx on public.reactions(user_id);
create index if not exists contributions_user_created_idx on public.contributions(user_id,created_at desc);
create index if not exists contributions_status_created_idx on public.contributions(status,created_at);
create index if not exists contributions_problem_idx on public.contributions(problem_id) where problem_id is not null;
create index if not exists contributions_solution_idx on public.contributions(solution_id) where solution_id is not null;
create index if not exists contribution_audit_contribution_idx on public.contribution_audit(contribution_id,created_at desc);
create index if not exists contribution_audit_moderator_idx on public.contribution_audit(moderator_id,created_at desc);
create index if not exists audit_events_created_idx on public.audit_events(created_at desc);
create index if not exists audit_events_type_idx on public.audit_events(event_type,created_at desc);
create index if not exists audit_events_actor_idx on public.audit_events(actor_id,created_at desc);
create index if not exists audit_events_target_idx on public.audit_events(target_type,target_id,created_at desc);
create index if not exists notifications_recipient_read_created_idx on public.notifications(recipient_id,read_at,created_at desc);
create index if not exists notifications_type_created_idx on public.notifications(type,created_at desc);
create index if not exists notifications_recipient_created_idx on public.notifications(recipient_id,created_at desc);
create index if not exists problem_timeline_problem_created_idx on public.problem_timeline(problem_id,created_at,id);
create index if not exists problems_latitude_idx on public.problems(latitude) where latitude is not null;
create index if not exists problems_longitude_idx on public.problems(longitude) where longitude is not null;

-- Safe replacements restore the public map contract and preserve the Sprint 25.1 signature.
create or replace function public.public_problem_coordinate(value double precision, "precision" text) returns double precision language sql immutable strict set search_path=public as $$ select case $2 when 'exact' then $1 when 'street' then round($1::numeric,3)::double precision when 'neighborhood' then round($1::numeric,2)::double precision when 'city' then round($1::numeric,1)::double precision when 'state' then round($1::numeric,0)::double precision end $$;
create or replace function public.get_problem_region_summary() returns table(state text,city text,total_problems bigint,in_progress bigint,resolved bigint,last_updated timestamptz) language sql stable security definer set search_path=public as $$ select state,city,count(*),count(*) filter(where status='Em execução'),count(*) filter(where status='Resolvido'),max(updated_at) from public.problems where latitude is not null and longitude is not null group by state,city order by state,city $$;
create or replace function public.get_public_problem_location(p_problem_id uuid) returns table(id uuid,title text,category text,status text,city text,state text,latitude double precision,longitude double precision,geolocation_precision text,updated_at timestamptz,source_verified_at timestamptz) language sql stable security definer set search_path=public as $$ select id,title,category,status,city,state,public.public_problem_coordinate(latitude,geolocation_precision),public.public_problem_coordinate(longitude,geolocation_precision),geolocation_precision,updated_at,source_verified_at from public.problems where id=p_problem_id and latitude is not null and longitude is not null $$;
create or replace function public.write_audit_event(p_event_type text,p_target_type text default null,p_target_id uuid default null,p_metadata jsonb default '{}'::jsonb) returns uuid language plpgsql security definer set search_path=public as $$ declare v_id uuid; begin insert into public.audit_events(actor_id,event_type,target_type,target_id,metadata) values(auth.uid(),p_event_type,p_target_type,p_target_id,coalesce(p_metadata,'{}')) returning id into v_id; return v_id; end $$;

-- Re-enable RLS and recreate only absent policies; existing policies are retained.
alter table public.reactions enable row level security; alter table public.contributions enable row level security; alter table public.contribution_audit enable row level security; alter table public.audit_events enable row level security; alter table public.notifications enable row level security; alter table public.problem_timeline enable row level security;
do $$ begin
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='reactions' and policyname='Users can read own reactions') then create policy "Users can read own reactions" on public.reactions for select to authenticated using(auth.uid()=user_id); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='reactions' and policyname='Users can create own reactions') then create policy "Users can create own reactions" on public.reactions for insert to authenticated with check(auth.uid()=user_id); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='notifications' and policyname='Users read only own notifications') then create policy "Users read only own notifications" on public.notifications for select to authenticated using(recipient_id=auth.uid()); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='problem_timeline' and policyname='Public reads problem timeline') then create policy "Public reads problem timeline" on public.problem_timeline for select to anon,authenticated using(true); end if;
end $$;
revoke all on function public.public_problem_coordinate(double precision,text) from public,anon,authenticated;
revoke all on function public.write_audit_event(text,text,uuid,jsonb) from public;
grant execute on function public.get_problem_region_summary() to anon,authenticated;
grant execute on function public.get_public_problem_location(uuid) to anon,authenticated;

-- Storage catalog writes are idempotent; no objects/content are removed.
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values ('avatars','avatars',true,5242880,array['image/jpeg','image/png','image/webp']),('problem-images','problem-images',true,5242880,array['image/jpeg','image/png','image/webp']),('solution-images','solution-images',true,5242880,array['image/jpeg','image/png','image/webp']) on conflict(id) do nothing;
do $$ begin if not exists(select 1 from pg_policies where schemaname='storage' and tablename='objects' and policyname='Public read image buckets') then create policy "Public read image buckets" on storage.objects for select using(bucket_id in ('avatars','problem-images','solution-images')); end if; end $$;
notify pgrst, 'reload schema';

-- Read-only catalog audit used by scripts/auditLegacySchema.ts. It exposes names,
-- never secrets, and lets the service role inspect complete structural expectations.
create or replace function public.audit_legacy_schema() returns jsonb language sql stable security definer set search_path=public,pg_catalog,information_schema as $$
 with required_tables(name) as (values ('profiles'),('problems'),('solutions'),('comments'),('favorites'),('reactions'),('contributions'),('contribution_audit'),('audit_events'),('notifications'),('problem_timeline')),
 required_columns(table_name,column_name) as (values ('profiles','social_links'),('profiles','website'),('profiles','organization'),('problems','source_metadata'),('problems','source_verified_at'),('problems','latitude'),('problems','longitude'),('comments','user_id'),('favorites','user_id'),('reactions','reaction_type'),('contributions','payload'),('notifications','recipient_id')),
 required_functions(name) as (values ('public.public_problem_coordinate(double precision,text)'),('public.get_problem_region_summary()'),('public.get_public_problem_location(uuid)'),('public.write_audit_event(text,text,uuid,jsonb)'),('public.get_reaction_summary(uuid,uuid)'),('public.review_contribution(uuid,text,text)'),('public.get_contribution_history(uuid,uuid)'),('public.update_user_role(uuid,text)'),('public.get_notifications(text,boolean,integer,integer)'),('public.get_unread_notification_count()'),('public.mark_notification_read(uuid)'),('public.mark_all_notifications_read()'),('public.publish_problem_update(uuid,text,text,text)'),('public.get_problem_timeline(uuid)')),
 missing as (
 select 'table:'||name item from required_tables where to_regclass('public.'||name) is null union all
 select 'column:'||table_name||'.'||column_name from required_columns r where not exists(select 1 from information_schema.columns c where c.table_schema='public' and c.table_name=r.table_name and c.column_name=r.column_name) union all
 select 'function:'||name from required_functions where to_regprocedure(name) is null union all
 select 'policy:storage.objects/Public read image buckets' where not exists(select 1 from pg_policies where schemaname='storage' and tablename='objects' and policyname='Public read image buckets') union all
 select 'bucket:'||id from (values ('avatars'),('problem-images'),('solution-images')) b(id) where not exists(select 1 from storage.buckets where buckets.id=b.id)
 ) select jsonb_build_object('ok',not exists(select 1 from missing),'missing',coalesce((select jsonb_agg(item order by item) from missing),'[]'::jsonb))
$$;
revoke all on function public.audit_legacy_schema() from public;
grant execute on function public.audit_legacy_schema() to service_role;

-- Exact Sprint 20 reaction RPC contract.
create or replace function public.get_reaction_summary(p_problem_id uuid default null, p_solution_id uuid default null)
returns table (reaction_type text, reaction_count bigint, selected_by_user boolean)
language sql stable security definer set search_path = public as $$
  select types.reaction_type,count(r.id)::bigint,coalesce(bool_or(r.user_id = auth.uid()), false)
  from (values ('useful'::text), ('liked'::text), ('interesting'::text)) types(reaction_type)
  left join public.reactions r on r.reaction_type=types.reaction_type and ((p_problem_id is not null and p_solution_id is null and r.problem_id=p_problem_id) or (p_problem_id is null and p_solution_id is not null and r.solution_id=p_solution_id))
  where ((p_problem_id is not null)::integer + (p_solution_id is not null)::integer)=1 group by types.reaction_type;
$$;
revoke all on function public.get_reaction_summary(uuid,uuid) from public;
grant execute on function public.get_reaction_summary(uuid,uuid) to anon,authenticated;

create or replace function public.is_contribution_moderator() returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.profiles where id=auth.uid() and role in ('curator','admin')); $$;
revoke all on function public.is_contribution_moderator() from public; grant execute on function public.is_contribution_moderator() to authenticated;
-- The full public history signature is retained; review uses this protected RPC.
create or replace function public.get_contribution_history(p_problem_id uuid default null,p_solution_id uuid default null)
returns table(id uuid,problem_id uuid,solution_id uuid,contribution_type text,payload jsonb,status text,rejection_reason text,created_at timestamptz,reviewed_at timestamptz,target_title text,author_name text,author_avatar_url text)
language sql stable security definer set search_path=public as $$ select c.id,c.problem_id,c.solution_id,c.contribution_type,c.payload,c.status,c.rejection_reason,c.created_at,c.reviewed_at,coalesce(p.title,s.title),coalesce(nullif(trim(a.display_name),''),nullif(trim(a.username),''),'Colaborador(a)'),a.avatar_url from public.contributions c join public.profiles a on a.id=c.user_id left join public.problems p on p.id=c.problem_id left join public.solutions s on s.id=c.solution_id where ((p_problem_id is not null)::integer+(p_solution_id is not null)::integer)=1 and c.status in ('approved','rejected') and ((p_problem_id is not null and c.problem_id=p_problem_id) or (p_solution_id is not null and c.solution_id=p_solution_id)) order by c.created_at desc; $$;
revoke all on function public.get_contribution_history(uuid,uuid) from public; grant execute on function public.get_contribution_history(uuid,uuid) to anon,authenticated;

-- Sprint 22 authorization helpers retain their original signatures.
create or replace function public.has_role(p_roles text[]) returns boolean language sql stable security definer set search_path=public as $$ select auth.uid() is not null and exists(select 1 from public.profiles where id=auth.uid() and role=any(p_roles)); $$;
create or replace function public.has_role(p_role text) returns boolean language sql stable security definer set search_path=public as $$ select public.has_role(array[p_role]); $$;
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$ select public.has_role('admin'); $$;
create or replace function public.can_review_contributions() returns boolean language sql stable security definer set search_path=public as $$ select public.has_role(array['curator','admin']); $$;
create or replace function public.can_moderate_comments() returns boolean language sql stable security definer set search_path=public as $$ select public.has_role(array['moderator','admin']); $$;
revoke all on function public.has_role(text[]) from public; revoke all on function public.has_role(text) from public; revoke all on function public.is_admin() from public; revoke all on function public.can_review_contributions() from public; revoke all on function public.can_moderate_comments() from public; grant execute on function public.has_role(text[]),public.has_role(text),public.is_admin(),public.can_review_contributions(),public.can_moderate_comments() to authenticated;

create or replace function public.review_contribution(p_contribution_id uuid, p_status text, p_rejection_reason text default null)
returns void language plpgsql security definer set search_path = public as $$
declare c public.contributions%rowtype; changes jsonb; change jsonb; column_name text; proposed jsonb;
begin
  if not public.is_contribution_moderator() then raise exception 'Not authorized' using errcode = '42501'; end if;
  if p_status not in ('approved', 'rejected') then raise exception 'Invalid status' using errcode = '22023'; end if;
  if p_status = 'rejected' and nullif(trim(p_rejection_reason), '') is null then raise exception 'Rejection reason is required' using errcode = '22023'; end if;
  select * into c from public.contributions where id = p_contribution_id for update;
  if not found then raise exception 'Contribution not found' using errcode = 'P0002'; end if;
  if c.status not in ('pending', 'reviewing') then raise exception 'Contribution already reviewed' using errcode = '22023'; end if;
  if p_status = 'approved' then
    changes := c.payload->'changes';
    for change in select value from jsonb_array_elements(changes) loop
      column_name := case change->>'field'
        when 'title' then 'title' when 'summary' then 'summary' when 'description' then 'description'
        when 'category' then 'category' when 'status' then 'status' when 'tags' then 'tags'
        when 'image' then 'image_url' when 'organization' then 'organization'
        when 'impactMetric' then 'impact_metric' when 'evidenceLinks' then 'evidence_links'
        else null end;
      if column_name is null then raise exception 'Field is not eligible for contribution' using errcode = '22023'; end if;
      proposed := change->'proposedValue';
      if c.problem_id is not null then
        if column_name not in ('title','summary','description','category','status','tags','image_url') then raise exception 'Invalid problem field' using errcode = '22023'; end if;
        if column_name = 'tags' then execute format('update public.problems set %I = $1, updated_at = timezone(''utc'', now()) where id = $2', column_name) using array(select jsonb_array_elements_text(proposed)), c.problem_id;
        else execute format('update public.problems set %I = $1, updated_at = timezone(''utc'', now()) where id = $2', column_name) using proposed #>> '{}', c.problem_id; end if;
      else
        if column_name not in ('title','summary','description','category','status','tags','image_url','organization','impact_metric','evidence_links') then raise exception 'Invalid solution field' using errcode = '22023'; end if;
        if column_name in ('tags','evidence_links') then execute format('update public.solutions set %I = $1, updated_at = timezone(''utc'', now()) where id = $2', column_name) using array(select jsonb_array_elements_text(proposed)), c.solution_id;
        else execute format('update public.solutions set %I = $1, updated_at = timezone(''utc'', now()) where id = $2', column_name) using proposed #>> '{}', c.solution_id; end if;
      end if;
    end loop;
  end if;
  update public.contributions set status = p_status, moderator_id = auth.uid(), rejection_reason = case when p_status = 'rejected' then trim(p_rejection_reason) else null end, reviewed_at = timezone('utc', now()) where id = c.id;
  insert into public.contribution_audit(contribution_id, moderator_id, action) values (c.id, auth.uid(), p_status);
end; $$;
revoke all on function public.review_contribution(uuid,text,text) from public; grant execute on function public.review_contribution(uuid,text,text) to authenticated;

create or replace function public.create_notification(p_recipient_id uuid,p_type text,p_title text,p_message text,p_target_type text default null,p_target_id uuid default null,p_action_url text default null,p_metadata jsonb default '{}'::jsonb,p_actor_id uuid default null) returns uuid language plpgsql security definer set search_path=public as $$ declare v_id uuid; v_metadata jsonb:=coalesce(p_metadata,'{}'::jsonb); begin if p_recipient_id is null or (p_actor_id is not null and p_actor_id=p_recipient_id) then return null; end if; if jsonb_typeof(v_metadata)<>'object' or pg_column_size(v_metadata)>4096 or v_metadata ?| array['password','token','secret','session','credential','api_key','mfa_secret'] then raise exception 'Invalid notification metadata' using errcode='22023'; end if; insert into public.notifications(recipient_id,actor_id,type,title,message,target_type,target_id,action_url,metadata) values(p_recipient_id,p_actor_id,p_type,trim(p_title),trim(p_message),nullif(trim(p_target_type),''),p_target_id,p_action_url,v_metadata) returning id into v_id; return v_id; end $$;
revoke all on function public.create_notification(uuid,text,text,text,text,uuid,text,jsonb,uuid) from public,anon,authenticated;
create or replace function public.get_unread_notification_count() returns bigint language plpgsql stable security definer set search_path=public as $$ begin if auth.uid() is null then raise exception 'Authentication required' using errcode='42501'; end if; return (select count(*) from public.notifications where recipient_id=auth.uid() and read_at is null); end $$;
create or replace function public.mark_notification_read(p_notification_id uuid) returns boolean language plpgsql security definer set search_path=public as $$ begin if auth.uid() is null then raise exception 'Authentication required' using errcode='42501'; end if; update public.notifications set read_at=coalesce(read_at,timezone('utc',now())) where id=p_notification_id and recipient_id=auth.uid(); return found; end $$;
create or replace function public.mark_all_notifications_read() returns integer language plpgsql security definer set search_path=public as $$ declare v_count integer; begin if auth.uid() is null then raise exception 'Authentication required' using errcode='42501'; end if; update public.notifications set read_at=timezone('utc',now()) where recipient_id=auth.uid() and read_at is null; get diagnostics v_count=row_count; return v_count; end $$;

create or replace function public.get_problem_timeline(p_problem_id uuid) returns table(id uuid,event_type text,title text,description text,official boolean,organization_name text,status_before text,status_after text,actor_name text,created_at timestamptz) language sql stable security definer set search_path=public as $$ select t.id,t.event_type,t.title,t.description,t.official,t.organization_name,t.status_before,t.status_after,coalesce(nullif(trim(p.display_name),''),nullif(trim(p.username),''),case when t.actor_id is null then 'Sistema' else 'Usuário da plataforma' end),t.created_at from public.problem_timeline t left join public.profiles p on p.id=t.actor_id where t.problem_id=p_problem_id and exists(select 1 from public.problems x where x.id=p_problem_id) order by t.created_at,t.id $$;
revoke all on function public.get_problem_timeline(uuid) from public; grant execute on function public.get_problem_timeline(uuid) to anon,authenticated;
create or replace function public.record_problem_timeline_sprint24() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_op='INSERT' then insert into public.problem_timeline(problem_id,actor_id,event_type,title,status_after) values(new.id,auth.uid(),'problem.created','Problema criado',new.status); elsif old.status is distinct from new.status then insert into public.problem_timeline(problem_id,actor_id,event_type,title,status_before,status_after) values(new.id,auth.uid(),'problem.status_changed',new.status,old.status,new.status); end if; return new; end $$;
drop trigger if exists record_problem_timeline_sprint24 on public.problems; create trigger record_problem_timeline_sprint24 after insert or update of status on public.problems for each row execute function public.record_problem_timeline_sprint24();

-- Complete Sprint 23 RPC and trigger contract.
create or replace function public.get_notifications(p_type text default null,p_unread_only boolean default false,p_limit integer default 20,p_offset integer default 0) returns table(id uuid,actor_id uuid,actor_name text,type text,title text,message text,target_type text,target_id uuid,action_url text,metadata jsonb,read_at timestamptz,created_at timestamptz) language plpgsql stable security definer set search_path=public as $$ begin if auth.uid() is null then raise exception 'Authentication required' using errcode='42501'; end if; return query select n.id,n.actor_id,coalesce(nullif(trim(p.display_name),''),nullif(trim(p.username),''),'Sistema'),n.type,n.title,n.message,n.target_type,n.target_id,n.action_url,n.metadata,n.read_at,n.created_at from public.notifications n left join public.profiles p on p.id=n.actor_id where n.recipient_id=auth.uid() and (p_type is null or n.type=p_type) and (not coalesce(p_unread_only,false) or n.read_at is null) order by n.created_at desc limit least(greatest(p_limit,1),100) offset greatest(p_offset,0); end $$;
revoke all on function public.get_notifications(text,boolean,integer,integer),public.get_unread_notification_count(),public.mark_notification_read(uuid),public.mark_all_notifications_read() from public,anon; grant execute on function public.get_notifications(text,boolean,integer,integer),public.get_unread_notification_count(),public.mark_notification_read(uuid),public.mark_all_notifications_read() to authenticated;
revoke all on public.notifications from anon; revoke insert,update,delete on public.notifications from authenticated; grant select on public.notifications to authenticated;
create or replace function public.notify_contribution_review_sprint23() returns trigger language plpgsql security definer set search_path=public as $$ begin if new.status in ('approved','rejected') and old.status is distinct from new.status then perform public.create_notification(new.user_id,'contribution.'||new.status,case new.status when 'approved' then 'Contribuição aprovada' else 'Contribuição rejeitada' end,case new.status when 'approved' then 'Sua contribuição foi aprovada e aplicada.' else 'Sua contribuição foi rejeitada. Consulte os detalhes da revisão.' end,'contribution',new.id,'/contributions/'||new.id,jsonb_build_object('status',new.status),auth.uid()); end if; return new; end $$;
drop trigger if exists notify_contribution_review_sprint23 on public.contributions; create trigger notify_contribution_review_sprint23 after update on public.contributions for each row execute function public.notify_contribution_review_sprint23();
create or replace function public.notify_comment_created_sprint23() returns trigger language plpgsql security definer set search_path=public as $$ declare v_owner uuid;v_parent_owner uuid;v_kind text;v_target uuid;v_url text; begin v_kind:=case when new.problem_id is not null then 'problem' else 'solution' end;v_target:=coalesce(new.problem_id,new.solution_id);v_url:='/'||v_kind||'s/'||v_target;if new.parent_id is not null then select user_id into v_parent_owner from public.comments where id=new.parent_id;perform public.create_notification(v_parent_owner,'comment.replied','Nova resposta ao seu comentário','Seu comentário recebeu uma nova resposta.',v_kind,v_target,v_url,jsonb_build_object('comment_id',new.id),new.user_id);end if;if new.problem_id is not null then select author_id into v_owner from public.problems where id=new.problem_id;else select author_id into v_owner from public.solutions where id=new.solution_id;end if;if new.parent_id is null or v_owner is distinct from v_parent_owner then perform public.create_notification(v_owner,'comment.created','Novo comentário','Seu conteúdo recebeu um novo comentário.',v_kind,v_target,v_url,jsonb_build_object('comment_id',new.id),new.user_id);end if;return new;end $$;
drop trigger if exists notify_comment_created_sprint23 on public.comments; create trigger notify_comment_created_sprint23 after insert on public.comments for each row execute function public.notify_comment_created_sprint23();
create or replace function public.notify_favorite_update_sprint23() returns trigger language plpgsql security definer set search_path=public as $$ declare f record;v_relevant boolean;v_kind text:=rtrim(tg_table_name,'s');begin if current_setting('app.official_update',true)='true' then return new;end if;v_relevant:=new.title is distinct from old.title or new.summary is distinct from old.summary or new.description is distinct from old.description or new.status is distinct from old.status or new.tags is distinct from old.tags;if not v_relevant then return new;end if;for f in execute format('select user_id from public.favorites where %I=$1',v_kind||'_id') using new.id loop perform public.create_notification(f.user_id,'favorite.content_updated','Conteúdo favorito atualizado','Um conteúdo que você favoritou recebeu uma atualização.',v_kind,new.id,'/'||v_kind||'s/'||new.id,'{}',auth.uid());end loop;return new;end $$;
drop trigger if exists notify_problem_favorites_sprint23 on public.problems; create trigger notify_problem_favorites_sprint23 after update on public.problems for each row execute function public.notify_favorite_update_sprint23(); drop trigger if exists notify_solution_favorites_sprint23 on public.solutions; create trigger notify_solution_favorites_sprint23 after update on public.solutions for each row execute function public.notify_favorite_update_sprint23();

-- Sprint 24 final roles/status and idempotent timeline backfill.
do $$ begin
 if not exists(select 1 from pg_constraint where conrelid='public.profiles'::regclass and conname='profiles_role_check') then alter table public.profiles add constraint profiles_role_check check(role in ('member','curator','moderator','verified_organization','admin')) not valid; end if;
 if not exists(select 1 from pg_constraint where conrelid='public.problems'::regclass and conname='problems_status_check') then alter table public.problems add constraint problems_status_check check(status in ('Reportado','Em análise','Em vistoria','Planejado','Licitado','Em execução','Parcialmente resolvido','Resolvido','Arquivado','Reaberto')) not valid; end if;
end $$;
alter table public.problems alter column status set default 'Reportado';
insert into public.problem_timeline(problem_id,event_type,title,status_after,created_at,metadata) select p.id,'problem.created','Problema criado',p.status,p.created_at,jsonb_build_object('backfilled',true) from public.problems p where not exists(select 1 from public.problem_timeline t where t.problem_id=p.id);
create or replace function public.publish_problem_update(p_problem_id uuid,p_title text,p_description text,p_status text default null) returns uuid language plpgsql security definer set search_path=public as $$ declare v_actor uuid:=auth.uid();v_role text;v_organization text;v_actor_name text;v_old_status text;v_event_id uuid;v_favorite record;begin if v_actor is null then raise exception 'Authentication required' using errcode='42501';end if;select p.role,nullif(trim(p.organization),''),coalesce(nullif(trim(p.display_name),''),nullif(trim(p.username),''),'Usuário da plataforma') into v_role,v_organization,v_actor_name from public.profiles p where p.id=v_actor;if v_role is null or v_role not in ('verified_organization','moderator','admin') then raise exception 'Not authorized to publish official updates' using errcode='42501';end if;if v_role='verified_organization' and v_organization is null then raise exception 'Verified organization profile requires an organization' using errcode='23514';end if;if length(trim(coalesce(p_title,''))) not between 1 and 160 or length(coalesce(p_description,''))>5000 then raise exception 'Invalid official update' using errcode='22023';end if;if p_status is not null and p_status not in ('Reportado','Em análise','Em vistoria','Planejado','Licitado','Em execução','Parcialmente resolvido','Resolvido','Arquivado','Reaberto') then raise exception 'Invalid problem status' using errcode='22023';end if;select status into v_old_status from public.problems where id=p_problem_id for update;if not found then raise exception 'Problem not found' using errcode='P0002';end if;insert into public.problem_timeline(problem_id,actor_id,event_type,title,description,official,organization_name,metadata) values(p_problem_id,v_actor,'problem.official_update',trim(p_title),nullif(trim(p_description),''),true,v_organization,'{}') returning id into v_event_id;if p_status is not null and p_status is distinct from v_old_status then perform set_config('app.official_update','true',true);update public.problems set status=p_status where id=p_problem_id;end if;perform public.write_audit_event('problem.updated','problem',p_problem_id,jsonb_strip_nulls(jsonb_build_object('official_update_id',v_event_id,'organization',v_organization,'actor_name',v_actor_name)));for v_favorite in select user_id from public.favorites where problem_id=p_problem_id and user_id<>v_actor loop perform public.create_notification(v_favorite.user_id,'favorite.content_updated','Atualização no problema','O problema recebeu atualização.','problem',p_problem_id,'/problems/'||p_problem_id,jsonb_build_object('official',true),v_actor);end loop;return v_event_id;end $$;
revoke all on function public.publish_problem_update(uuid,text,text,text) from public,anon;grant execute on function public.publish_problem_update(uuid,text,text,text) to authenticated;
create or replace function public.update_user_role(p_user_id uuid,p_role text) returns void language plpgsql security definer set search_path=public as $$ declare old_role text;admin_count integer;friendly text;begin if not public.is_admin() then raise exception 'Not authorized' using errcode='42501';end if;if p_role not in ('member','curator','moderator','verified_organization','admin') then raise exception 'Invalid role' using errcode='22023';end if;select role into old_role from public.profiles where id=p_user_id for update;if not found then raise exception 'User not found' using errcode='P0002';end if;if old_role='admin' and p_role<>'admin' then select count(*) into admin_count from public.profiles where role='admin';if admin_count<=1 then raise exception 'The last administrator cannot be removed' using errcode='23514';end if;end if;if old_role=p_role then return;end if;perform set_config('app.role_change_authorized','true',true);update public.profiles set role=p_role where id=p_user_id;perform public.write_audit_event('user.role_changed','user',p_user_id,jsonb_build_object('previous_role',old_role,'new_role',p_role));friendly:=case p_role when 'member' then 'Membro' when 'curator' then 'Curador' when 'moderator' then 'Moderador' when 'verified_organization' then 'Organização verificada' else 'Administrador' end;perform public.create_notification(p_user_id,'user.role_changed','Seu papel foi atualizado','Seu novo papel é '||friendly||'.','user',p_user_id,'/profile',jsonb_build_object('role',p_role),auth.uid());end $$;
revoke all on function public.update_user_role(uuid,text) from public;grant execute on function public.update_user_role(uuid,text) to authenticated;
do $$ begin
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='reactions' and policyname='Users can delete own reactions') then create policy "Users can delete own reactions" on public.reactions for delete to authenticated using(auth.uid()=user_id); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='contributions' and policyname='Users read own contributions and moderators read all') then create policy "Users read own contributions and moderators read all" on public.contributions for select to authenticated using(user_id=auth.uid() or public.is_contribution_moderator()); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='contributions' and policyname='Users create own contributions') then create policy "Users create own contributions" on public.contributions for insert to authenticated with check(user_id=auth.uid() and status='pending' and moderator_id is null and reviewed_at is null and rejection_reason is null); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='contribution_audit' and policyname='Moderators read contribution audit') then create policy "Moderators read contribution audit" on public.contribution_audit for select to authenticated using(public.is_contribution_moderator()); end if;
end $$;

-- Sprint 22 audit trail: replace the earlier safe definition with the complete contract.
create or replace function public.write_audit_event(p_event_type text,p_target_type text default null,p_target_id uuid default null,p_metadata jsonb default '{}'::jsonb) returns uuid language plpgsql security definer set search_path=public as $$ declare v_id uuid; begin if auth.uid() is null then raise exception 'Authentication required' using errcode='42501'; end if; if jsonb_typeof(coalesce(p_metadata,'{}'::jsonb))<>'object' or pg_column_size(coalesce(p_metadata,'{}'::jsonb))>4096 or coalesce(p_metadata,'{}'::jsonb) ?| array['password','token','secret','session','credential','api_key','mfa_secret'] then raise exception 'Invalid audit metadata' using errcode='22023'; end if; insert into public.audit_events(actor_id,event_type,target_type,target_id,metadata) values(auth.uid(),p_event_type,nullif(trim(p_target_type),''),p_target_id,coalesce(p_metadata,'{}')) returning id into v_id; return v_id; end $$;
revoke all on function public.write_audit_event(text,text,uuid,jsonb) from public;
create or replace function public.audit_domain_change() returns trigger language plpgsql security definer set search_path=public as $$ declare v_type text;v_id uuid;begin if auth.uid() is null then return coalesce(new,old);end if;v_type:=case when tg_table_name='problems' and tg_op='INSERT' then 'problem.created' when tg_table_name='problems' and tg_op='UPDATE' then 'problem.updated' when tg_table_name='problems' and tg_op='DELETE' then 'problem.deleted' when tg_table_name='solutions' and tg_op='INSERT' then 'solution.created' when tg_table_name='solutions' and tg_op='UPDATE' then 'solution.updated' when tg_table_name='solutions' and tg_op='DELETE' then 'solution.deleted' else null end;if v_type is null then raise exception 'Unsupported audit trigger source' using errcode='22023';end if;v_id:=case when tg_op='DELETE' then old.id else new.id end;perform public.write_audit_event(v_type,rtrim(tg_table_name,'s'),v_id,'{}'::jsonb);return coalesce(new,old);end $$;
drop trigger if exists audit_problems_change on public.problems;create trigger audit_problems_change after insert or update or delete on public.problems for each row execute function public.audit_domain_change();drop trigger if exists audit_solutions_change on public.solutions;create trigger audit_solutions_change after insert or update or delete on public.solutions for each row execute function public.audit_domain_change();
create or replace function public.reject_audit_mutation() returns trigger language plpgsql as $$ begin raise exception 'Audit events are immutable' using errcode='42501';end $$;drop trigger if exists audit_events_no_update_delete on public.audit_events;create trigger audit_events_no_update_delete before update or delete on public.audit_events for each row execute function public.reject_audit_mutation();
do $$ begin if not exists(select 1 from pg_policies where schemaname='public' and tablename='audit_events' and policyname='Admins read audit events') then create policy "Admins read audit events" on public.audit_events for select to authenticated using(public.is_admin());end if;end $$;revoke insert,update,delete on public.audit_events from anon,authenticated;

-- Preserve comment authors while converging exactly one authoritative user_id column.
do $$ declare has_author boolean; has_user boolean; begin
 select exists(select 1 from information_schema.columns where table_schema='public' and table_name='comments' and column_name='author_id'), exists(select 1 from information_schema.columns where table_schema='public' and table_name='comments' and column_name='user_id') into has_author,has_user;
 if has_author and not has_user then alter table public.comments rename column author_id to user_id;
 elsif not has_author and not has_user then raise exception 'Cannot reconcile comments: neither author_id nor user_id exists';
 elsif has_author and has_user then
   if exists(select 1 from public.comments where author_id is not null and user_id is not null and author_id is distinct from user_id) then raise exception 'Cannot reconcile comments: author_id and user_id diverge'; end if;
   update public.comments set user_id=author_id where user_id is null;
   -- author_id is removed only after equivalence is proven: user_id is the sole source of truth.
   alter table public.comments drop column author_id;
 end if;
 if exists(select 1 from public.comments where user_id is null) then raise exception 'Cannot reconcile comments: user_id would be null'; end if;
 alter table public.comments alter column user_id set not null;
end $$;
do $$ begin
 if not exists(select 1 from pg_constraint where conrelid='public.comments'::regclass and conname='comments_user_id_fkey') then alter table public.comments add constraint comments_user_id_fkey foreign key(user_id) references auth.users(id) on delete cascade not valid; end if;
 if not exists(select 1 from pg_constraint where conrelid='public.comments'::regclass and conname='comments_user_profile_fkey') then alter table public.comments add constraint comments_user_profile_fkey foreign key(user_id) references public.profiles(id) on delete cascade not valid; end if;
end $$;
create index if not exists comments_user_id_idx on public.comments(user_id);
alter table public.comments enable row level security;
do $$ begin
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='comments' and policyname='Authenticated users can create comments') then create policy "Authenticated users can create comments" on public.comments for insert to authenticated with check(auth.uid()=user_id); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='comments' and policyname='Authors can update own comments') then create policy "Authors can update own comments" on public.comments for update to authenticated using(auth.uid()=user_id) with check(auth.uid()=user_id); end if;
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='comments' and policyname='Authors can delete own comments') then create policy "Authors can delete own comments" on public.comments for delete to authenticated using(auth.uid()=user_id); end if;
end $$;
create table if not exists public.comment_reports(id uuid primary key default gen_random_uuid(),comment_id uuid not null references public.comments(id) on delete cascade,reporter_id uuid not null references public.profiles(id) on delete cascade,reason text not null,created_at timestamptz not null default timezone('utc',now()),constraint comment_reports_reason_check check(char_length(btrim(reason)) between 1 and 1000),constraint comment_reports_unique_reporter_per_comment unique(comment_id,reporter_id));
create index if not exists comment_reports_comment_id_idx on public.comment_reports(comment_id);create index if not exists comment_reports_reporter_id_idx on public.comment_reports(reporter_id);alter table public.comment_reports enable row level security;
create or replace function public.sprint20_protect_comment_fields() returns trigger language plpgsql set search_path=public as $$ begin if new.user_id is distinct from old.user_id or new.problem_id is distinct from old.problem_id or new.solution_id is distinct from old.solution_id or new.created_at is distinct from old.created_at then raise exception 'Comment ownership and target cannot be changed' using errcode='42501';end if;if new.content is distinct from old.content then new.edited:=true;end if;return new;end $$;drop trigger if exists sprint20_protect_comment_fields_before_update on public.comments;create trigger sprint20_protect_comment_fields_before_update before update on public.comments for each row execute function public.sprint20_protect_comment_fields();

-- Replace named legacy constraints only when their definitions differ, after data validation.
do $$ declare def text; begin
 select pg_get_constraintdef(oid) into def from pg_constraint where conrelid='public.profiles'::regclass and conname='profiles_role_check';
 if def is distinct from 'CHECK ((role = ANY (ARRAY[''member''::text, ''curator''::text, ''moderator''::text, ''verified_organization''::text, ''admin''::text])))' then
  if exists(select 1 from public.profiles where role not in ('member','curator','moderator','verified_organization','admin')) then raise exception 'Cannot reconcile profiles_role_check: invalid existing role values'; end if;
  alter table public.profiles drop constraint if exists profiles_role_check; alter table public.profiles add constraint profiles_role_check check(role in ('member','curator','moderator','verified_organization','admin')); end if;
 select pg_get_constraintdef(oid) into def from pg_constraint where conrelid='public.problems'::regclass and conname='problems_status_check';
 if def is distinct from 'CHECK ((status = ANY (ARRAY[''Reportado''::text, ''Em análise''::text, ''Em vistoria''::text, ''Planejado''::text, ''Licitado''::text, ''Em execução''::text, ''Parcialmente resolvido''::text, ''Resolvido''::text, ''Arquivado''::text, ''Reaberto''::text])))' then
  if exists(select 1 from public.problems where status not in ('Reportado','Em análise','Em vistoria','Planejado','Licitado','Em execução','Parcialmente resolvido','Resolvido','Arquivado','Reaberto')) then raise exception 'Cannot reconcile problems_status_check: invalid existing status values'; end if;
  alter table public.problems drop constraint if exists problems_status_check; alter table public.problems add constraint problems_status_check check(status in ('Reportado','Em análise','Em vistoria','Planejado','Licitado','Em execução','Parcialmente resolvido','Resolvido','Arquivado','Reaberto')); end if;
end $$;

-- Complete catalog audit: one missing/incompatible functional object keeps ok=false.
create or replace function public.audit_legacy_schema() returns jsonb language sql stable security definer set search_path=public,pg_catalog,information_schema as $$
with required_tables(n) as(values('reactions'),('contributions'),('contribution_audit'),('audit_events'),('notifications'),('problem_timeline'),('comment_reports')),
required_columns(t,c,typ) as(values('comments','user_id','uuid'),('comment_reports','reason','text'),('notifications','action_url','text'),('contributions','contribution_type','text')),
required_functions(s) as(values('public.write_audit_event(text,text,uuid,jsonb)'),('public.audit_domain_change()'),('public.get_reaction_summary(uuid,uuid)'),('public.review_contribution(uuid,text,text)'),('public.get_notifications(text,boolean,integer,integer)'),('public.publish_problem_update(uuid,text,text,text)'),('public.validate_comment_target_and_depth()'),('public.refresh_target_comment_count(uuid,uuid)'),('public.sync_comment_count()'),('public.mark_comment_best_answer(uuid)'),('public.report_comment(uuid,text)'),('public.list_reported_comments()'),('public.moderate_comment_visibility(uuid,text)'),('public.set_domain_updated_at()')),
required_indexes(n) as(values('comments_user_id_idx'),('comment_reports_comment_id_idx'),('comment_reports_reporter_id_idx'),('notifications_recipient_created_idx'),('notifications_recipient_read_created_idx'),('notifications_type_created_idx')),
required_policies(t,n) as(values('comments','Authenticated users can create comments'),('comments','Authors can update own comments'),('comments','Authors can delete own comments'),('audit_events','Admins read audit events'),('notifications','Users read only own notifications'),('comments','Public can read comments'),('comment_reports','Moderators can read comment reports')),
required_triggers(n) as(values('audit_problems_change'),('audit_solutions_change'),('audit_events_no_update_delete'),('sprint20_protect_comment_fields_before_update'),('validate_comment_target_and_depth_before_write'),('set_comments_updated_at_before_update'),('sync_comment_count_after_insert'),('sync_comment_count_after_update'),('sync_comment_count_after_delete')),
missing(item) as(select 'table:'||n from required_tables where to_regclass('public.'||n)is null union all select 'column:'||t||'.'||c from required_columns r where not exists(select 1 from information_schema.columns x where x.table_schema='public' and x.table_name=r.t and x.column_name=r.c and x.data_type=r.typ) union all select 'function:'||s from required_functions where to_regprocedure(s)is null union all select 'index:'||n from required_indexes where not exists(select 1 from pg_indexes where schemaname='public' and indexname=n) union all select 'policy:'||t||'.'||n from required_policies r where not exists(select 1 from pg_policies where schemaname='public' and tablename=r.t and policyname=r.n) union all select 'trigger:'||n from required_triggers where not exists(select 1 from pg_trigger where tgname=n and not tgisinternal) union all select 'comments:user_id-null' where exists(select 1 from public.comments where user_id is null) union all select 'comments:author-id-still-present' where exists(select 1 from information_schema.columns where table_schema='public' and table_name='comments' and column_name='author_id') union all select 'constraint:comments_user_id_fkey' where not exists(select 1 from pg_constraint where conrelid='public.comments'::regclass and conname='comments_user_id_fkey') union all select 'constraint:comments_user_profile_fkey' where not exists(select 1 from pg_constraint where conrelid='public.comments'::regclass and conname='comments_user_profile_fkey') union all select 'grant:authenticated-report-comment' where not has_function_privilege('authenticated','public.report_comment(uuid,text)','execute') union all select 'grant:authenticated-best-answer' where not has_function_privilege('authenticated','public.mark_comment_best_answer(uuid)','execute') union all select 'grant:authenticated-list-reported' where not has_function_privilege('authenticated','public.list_reported_comments()','execute') union all select 'grant:authenticated-moderate-comment' where not has_function_privilege('authenticated','public.moderate_comment_visibility(uuid,text)','execute') union all select 'grant:anon-report-comment' where has_function_privilege('anon','public.report_comment(uuid,text)','execute') union all select 'grant:comment-reports-write' where has_table_privilege('authenticated','public.comment_reports','insert,update,delete') union all select 'grant:anon-comment-reports' where has_table_privilege('anon','public.comment_reports','select,insert,update,delete') union all select 'rls:comment_reports' where not (select relrowsecurity from pg_class where oid='public.comment_reports'::regclass) union all select 'rls:comments' where not (select relrowsecurity from pg_class where oid='public.comments'::regclass) union all select 'bucket:'||id from(values('avatars'),('problem-images'),('solution-images')) b(id) where not exists(select 1 from storage.buckets where buckets.id=b.id)) select jsonb_build_object('ok',not exists(select 1 from missing),'missing',coalesce((select jsonb_agg(item order by item) from missing),'[]'::jsonb)) $$;
revoke all on function public.audit_legacy_schema() from public;grant execute on function public.audit_legacy_schema() to service_role;
-- Comment report access stays mediated by the original report/moderation RPC contract.
do $$ begin
 if not exists(select 1 from pg_policies where schemaname='public' and tablename='comment_reports' and policyname='Moderators can read comment reports') then create policy "Moderators can read comment reports" on public.comment_reports for select to authenticated using(exists(select 1 from public.profiles where id=auth.uid() and role in ('moderator','admin'))); end if;
end $$;
revoke all on public.comment_reports from anon;
revoke insert,update,delete on public.comment_reports from authenticated;

-- Final comment-report contract uses the converged user_id ownership column.
create or replace function public.report_comment(p_comment_id uuid,p_reason text) returns uuid language plpgsql security definer set search_path=public as $$ declare reporter_id uuid:=auth.uid();begin if reporter_id is null then raise exception 'Authentication required' using errcode='42501';end if;if nullif(btrim(p_reason),'') is null or char_length(btrim(p_reason)) not between 1 and 1000 then raise exception 'Invalid report reason' using errcode='23514';end if;if not exists(select 1 from public.comments where id=p_comment_id and user_id<>reporter_id) then raise exception 'Comment report was not accepted' using errcode='42501';end if;insert into public.comment_reports(comment_id,reporter_id,reason) values(p_comment_id,reporter_id,btrim(p_reason));return p_comment_id;end $$;
create or replace function public.mark_comment_best_answer(p_comment_id uuid) returns uuid language plpgsql security definer set search_path=public as $$ declare c public.comments%rowtype;begin if auth.uid() is null then raise exception 'Authentication required' using errcode='42501';end if;select * into c from public.comments where id=p_comment_id;if not found then raise exception 'Comment not found' using errcode='P0002';end if;if c.problem_id is not null and not exists(select 1 from public.problems where id=c.problem_id and author_id=auth.uid()) then raise exception 'Only the problem author can mark the best answer' using errcode='42501';end if;if c.solution_id is not null and not exists(select 1 from public.solutions where id=c.solution_id and author_id=auth.uid()) then raise exception 'Only the solution author can mark the best answer' using errcode='42501';end if;update public.comments set best_answer=false where (c.problem_id is not null and problem_id=c.problem_id) or(c.solution_id is not null and solution_id=c.solution_id);update public.comments set best_answer=true where id=p_comment_id;return p_comment_id;end $$;
create or replace function public.moderate_comment_visibility(p_comment_id uuid,p_visibility text) returns uuid language plpgsql security definer set search_path=public as $$ begin if not exists(select 1 from public.profiles where id=auth.uid() and role in ('moderator','admin')) then raise exception 'Only moderators can moderate comments' using errcode='42501';end if;if p_visibility not in('visible','hidden','removed') then raise exception 'Invalid visibility' using errcode='23514';end if;update public.comments set visibility=p_visibility,deleted=p_visibility='removed' where id=p_comment_id;if not found then raise exception 'Comment not found' using errcode='P0002';end if;return p_comment_id;end $$;
revoke all on function public.report_comment(uuid,text) from public;grant execute on function public.report_comment(uuid,text) to authenticated;revoke all on function public.mark_comment_best_answer(uuid) from public;grant execute on function public.mark_comment_best_answer(uuid) to authenticated;revoke all on function public.moderate_comment_visibility(uuid,text) from public;grant execute on function public.moderate_comment_visibility(uuid,text) to authenticated;

-- Complete comment tree, counters and moderation contract (user_id is authoritative).
create or replace function public.validate_comment_target_and_depth() returns trigger language plpgsql set search_path=public as $$ declare parent_record public.comments%rowtype;reply_depth integer:=1;begin if new.parent_id is null then return new;end if;select * into parent_record from public.comments where id=new.parent_id;if not found then raise exception 'Parent comment not found' using errcode='23503';end if;if parent_record.problem_id is distinct from new.problem_id or parent_record.solution_id is distinct from new.solution_id then raise exception 'Reply must target the same problem or solution as its parent' using errcode='23514';end if;with recursive ancestors as(select id,parent_id,1 depth from public.comments where id=new.parent_id union all select p.id,p.parent_id,a.depth+1 from public.comments p join ancestors a on a.parent_id=p.id) select coalesce(max(depth),0)+1 into reply_depth from ancestors;if reply_depth>3 then raise exception 'Replies are allowed up to three levels' using errcode='23514';end if;return new;end $$;
drop trigger if exists validate_comment_target_and_depth_before_write on public.comments;create trigger validate_comment_target_and_depth_before_write before insert or update on public.comments for each row execute function public.validate_comment_target_and_depth();
create or replace function public.refresh_target_comment_count(p_problem_id uuid,p_solution_id uuid) returns void language plpgsql set search_path=public as $$ begin if p_problem_id is not null then update public.problems set comments=(select count(*) from public.comments where problem_id=p_problem_id and deleted=false and visibility<>'removed') where id=p_problem_id;end if;if p_solution_id is not null then update public.solutions set comments=(select count(*) from public.comments where solution_id=p_solution_id and deleted=false and visibility<>'removed') where id=p_solution_id;end if;end $$;
create or replace function public.sync_comment_count() returns trigger language plpgsql set search_path=public as $$ begin if tg_op='INSERT' then perform public.refresh_target_comment_count(new.problem_id,new.solution_id);return new;elsif tg_op='DELETE' then perform public.refresh_target_comment_count(old.problem_id,old.solution_id);return old;elsif tg_op='UPDATE' then if new.deleted is distinct from old.deleted or new.visibility is distinct from old.visibility or new.problem_id is distinct from old.problem_id or new.solution_id is distinct from old.solution_id then perform public.refresh_target_comment_count(old.problem_id,old.solution_id);perform public.refresh_target_comment_count(new.problem_id,new.solution_id);end if;return new;end if;raise exception 'Unsupported comment trigger operation';end $$;
drop trigger if exists sync_comment_count_after_insert on public.comments;create trigger sync_comment_count_after_insert after insert on public.comments for each row execute function public.sync_comment_count();drop trigger if exists sync_comment_count_after_update on public.comments;create trigger sync_comment_count_after_update after update on public.comments for each row execute function public.sync_comment_count();drop trigger if exists sync_comment_count_after_delete on public.comments;create trigger sync_comment_count_after_delete after delete on public.comments for each row execute function public.sync_comment_count();
create or replace function public.set_domain_updated_at() returns trigger language plpgsql set search_path=public as $$ begin new.updated_at:=timezone('utc',now());return new;end $$;
drop trigger if exists set_comments_updated_at_before_update on public.comments;create trigger set_comments_updated_at_before_update before update on public.comments for each row execute function public.set_domain_updated_at();
do $$ begin if not exists(select 1 from pg_policies where schemaname='public' and tablename='comments' and policyname='Public can read comments') then create policy "Public can read comments" on public.comments for select to anon,authenticated using(deleted=false and visibility='visible');end if;end $$;
create or replace function public.list_reported_comments() returns table(id uuid,user_id uuid,parent_id uuid,problem_id uuid,solution_id uuid,content text,edited boolean,deleted boolean,visibility text,best_answer boolean,reports jsonb,created_at timestamptz,updated_at timestamptz,display_name text,username text,avatar_url text) language sql security definer set search_path=public as $$ select c.id,c.user_id,c.parent_id,c.problem_id,c.solution_id,c.content,c.edited,c.deleted,c.visibility,c.best_answer,coalesce(jsonb_agg(jsonb_build_object('userId',cr.reporter_id::text,'reason',cr.reason,'createdAt',cr.created_at::text) order by cr.created_at) filter(where cr.id is not null),'[]'::jsonb),c.created_at,c.updated_at,p.display_name,p.username,p.avatar_url from public.comments c join public.comment_reports cr on cr.comment_id=c.id left join public.profiles p on p.id=c.user_id where exists(select 1 from public.profiles m where m.id=auth.uid() and m.role in('moderator','admin')) group by c.id,p.display_name,p.username,p.avatar_url order by c.updated_at desc $$;
revoke all on function public.list_reported_comments() from public;grant execute on function public.list_reported_comments() to authenticated;
